class InMemoryPaymentGateway:
    def charge(self, amount: Decimal, payment_method: Dict[str, Any]) -> PaymentResult:
        if amount < Decimal("0.00"):
            return PaymentResult(False, None, "Invalid charge amount")
        if amount == Decimal("0.00"):
            return PaymentResult(True, f"txn_{uuid.uuid4().hex}", "No charge required")
        if not payment_method or not payment_method.get("valid", False):
            return PaymentResult(False, None, "Payment method declined")
        return PaymentResult(True, f"txn_{uuid.uuid4().hex}", "Approved")


class InMemoryOrderStore:
    def __init__(self) -> None:
        self.orders: List[Dict[str, Any]] = []

    def create(self, order_data: Dict[str, Any]) -> Dict[str, Any]:
        record = {
            "order_id": f"ord_{uuid.uuid4().hex}",
            **order_data,
        }
        self.orders.append(record)
        return record


def validate_cart_items(cart_items: List[CartItem]) -> Dict[str, Any]:
    if not cart_items:
        raise ValidationError("Cart is empty")

    validated_items = []
    subtotal = money("0.00")
    taxable_subtotal = money("0.00")

    for item in cart_items:
        if not item.active:
            raise ValidationError(f"Item {item.sku} is inactive")
        if item.quantity <= 0:
            raise ValidationError(f"Item {item.sku} has invalid quantity")
        if item.stock < item.quantity:
            raise ValidationError(f"Insufficient stock for item {item.sku}")
        if item.unit_price < Decimal("0.00"):
            raise ValidationError(f"Item {item.sku} has invalid price")

        line_subtotal = item.subtotal()
        subtotal += line_subtotal
        if item.taxable:
            taxable_subtotal += line_subtotal

        validated_items.append(
            {
                "sku": item.sku,
                "name": item.name,
                "unit_price": money(item.unit_price),
                "quantity": item.quantity,
                "taxable": item.taxable,
                "line_subtotal": money(line_subtotal),
            }
        )

    return {
        "items": validated_items,
        "subtotal": money(subtotal),
        "taxable_subtotal": money(taxable_subtotal),
    }


def apply_discount_codes(
    user: User,
    validated_cart: Dict[str, Any],
    discount_codes: List[str],
    discount_catalog: Dict[str, DiscountCode],
) -> Dict[str, Any]:
    subtotal = money(validated_cart["subtotal"])
    taxable_subtotal = money(validated_cart["taxable_subtotal"])
    total_discount = money("0.00")
    taxable_discount = money("0.00")
    applied_discounts = []

    for raw_code in discount_codes:
        code_key = raw_code.strip().upper()
        if code_key not in discount_catalog:
            raise ValidationError(f"Unknown discount code: {raw_code}")

        discount = discount_catalog[code_key]

        if not discount.is_user_allowed(user):
            raise PermissionError(f"User not permitted to use discount code: {code_key}")

        if subtotal < discount.min_subtotal:
            raise ValidationError(f"Discount code {code_key} requires minimum subtotal of {discount.min_subtotal}")

        if discount.applies_to_taxable_only:
            base_amount = max(money(taxable_subtotal - taxable_discount), money("0.00"))
        else:
            base_amount = max(money(subtotal - total_discount), money("0.00"))

        if discount.kind == "percent":
            discount_amount = money(base_amount * (discount.value / Decimal("100")))
        elif discount.kind == "fixed":
            discount_amount = min(money(discount.value), base_amount)
        else:
            raise ValidationError(f"Invalid discount type for code: {code_key}")

        total_discount += discount_amount
        if discount.applies_to_taxable_only:
            taxable_discount += discount_amount
        else:
            remaining_taxable = max(money(taxable_subtotal - taxable_discount), money("0.00"))
            taxable_portion = min(discount_amount, remaining_taxable)
            taxable_discount += taxable_portion

        applied_discounts.append(
            {
                "code": code_key,
                "kind": discount.kind,
                "value": money(discount.value),
                "amount": money(discount_amount),
                "applies_to_taxable_only": discount.applies_to_taxable_only,
            }
        )

    discounted_subtotal = max(money(subtotal - total_discount), money("0.00"))
    discounted_taxable_subtotal = max(money(taxable_subtotal - taxable_discount), money("0.00"))

    return {
        **validated_cart,
        "applied_discounts": applied_discounts,
        "discount_total": money(total_discount),
        "discounted_subtotal": money(discounted_subtotal),
        "discounted_taxable_subtotal": money(discounted_taxable_subtotal),
    }


def calculate_tax(discounted_cart: Dict[str, Any], tax_rate: Decimal) -> Dict[str, Any]:
    if tax_rate < Decimal("0.00"):
        raise ValidationError("Tax rate cannot be negative")

    taxable_amount = money(discounted_cart["discounted_taxable_subtotal"])
    tax = money(taxable_amount * tax_rate)
    total = money(discounted_cart["discounted_subtotal"] + tax)

    return {
        **discounted_cart,
        "tax_rate": tax_rate,
        "tax": tax,
        "total": total,
    }


def process_payment(
    taxed_cart: Dict[str, Any],
    payment_method: Dict[str, Any],
    payment_gateway: InMemoryPaymentGateway,
) -> Dict[str, Any]:
    amount = money(taxed_cart["total"])
    payment_result = payment_gateway.charge(amount, payment_method)

    if not payment_result.success:
        raise PaymentError(payment_result.message)

    return {
        **taxed_cart,
        "payment": {
            "success": True,
            "transaction_id": payment_result.transaction_id,
            "message": payment_result.message,
            "amount_charged": amount,
        },
    }


def create_order_record(
    user: User,
    paid_checkout: Dict[str, Any],
    order_store: InMemoryOrderStore,
) -> Dict[str, Any]:
    order_data = {
        "user_id": user.user_id,
        "user_tier": user.tier,
        "items": paid_checkout["items"],
        "subtotal": paid_checkout["subtotal"],
        "discount_total": paid_checkout["discount_total"],
        "discounts": paid_checkout["applied_discounts"],
        "discounted_subtotal": paid_checkout["discounted_subtotal"],
        "tax_rate": paid_checkout["tax_rate"],
        "tax": paid_checkout["tax"],
        "total": paid_checkout["total"],
        "payment": paid_checkout["payment"],
        "status": "paid",
    }
    return order_store.create(order_data)


def checkout(
    user: User,
    cart_items: List[CartItem],
    discount_codes: List[str],
    tax_rate: Decimal,
    payment_method: Dict[str, Any],
    discount_catalog: Dict[str, DiscountCode],
    payment_gateway: Optional[InMemoryPaymentGateway] = None,
    order_store: Optional[InMemoryOrderStore] = None,
) -> Dict[str, Any]:
    payment_gateway = payment_gateway or InMemoryPaymentGateway()
    order_store = order_store or InMemoryOrderStore()

    step1 = validate_cart_items(cart_items)
    step2 = apply_discount_codes(user, step1, discount_codes, discount_catalog)
    step3 = calculate_tax(step2, tax_rate)
    step4 = process_payment(step3, payment_method, payment_gateway)
    step5 = create_order_record(user, step4, order_store)

    return {
        "validated_cart": step1,
        "discounted_cart": step2,
        "taxed_cart": step3,
        "paid_checkout": step4,
        "order": step5,
    }


